{
  "terms": [
    {
      "term": "Transposition",
      "simpleDefinition": "The process of rearranging a formula to make a different letter the subject.",
      "anchor": "The 'Golden Rule': Whatever you do to one side of the equals sign, you must do to the other.",
      "misconception": "Thinking you can move a number to the other side without reversing its mathematical operation (e.g., changing a multiply to a divide)."
    },
    {
      "term": "Indices",
      "simpleDefinition": "Small numbers (powers) that tell you how many times to multiply a base number by itself.",
      "anchor": "Using powers of 10 to represent large values like kilo (10³) or small values like milli (10⁻³).",
      "misconception": "Believing that 10³ means 10 multiplied by 3 (30) rather than 10 x 10 x 10 (1000)."
    },
    {
      "term": "Pythagoras’ Theorem",
      "simpleDefinition": "A mathematical rule used to find the length of a missing side in a right-angled triangle.",
      "anchor": "Calculating the longest side (hypotenuse) of an impedance triangle using the formula a² + b² = c².",
      "misconception": "Forgetting to take the square root of the final sum to find the actual length of the side."
    },
    {
      "term": "SOH CAH TOA",
      "simpleDefinition": "A mnemonic used to remember the three main trigonometric ratios: Sine, Cosine, and Tangent.",
      "anchor": "Using the ratio of sides to find the phase angle in an AC circuit triangle.",
      "misconception": "Confusing the 'Opposite' and 'Adjacent' sides by not looking at where they sit in relation to the specific angle being measured."
    },
    {
      "term": "Algebra",
      "simpleDefinition": "A branch of maths where letters and symbols are used to represent numbers in formulas.",
      "anchor": "Using Ohm’s Law (V = I x R) where letters represent Voltage, Current, and Resistance.",
      "misconception": "Treating the letters as just labels rather than variables that hold numerical values."
    },
    {
      "term": "Mean",
      "simpleDefinition": "The mathematical average found by adding a set of values together and dividing by the number of values.",
      "anchor": "Finding the average of three separate Earth Loop Impedance test results.",
      "misconception": "Assuming 'average' always refers to the mean, when it could technically refer to the median or mode in different contexts."
    }
  ],
  "anchorPhrases": [
    "Whatever you do to one side, you must do to the other.",
    "SOH CAH TOA: Sine = Opposite/Hypotenuse, Cosine = Adjacent/Hypotenuse, Tangent = Opposite/Adjacent.",
    "Indices are powers of 10 used for scaling units like kilo and milli.",
    "The hypotenuse is always the longest side, opposite the right angle."
  ],
  "misconceptionTargets": [
    "Moving a multiplier to the other side of the equation and keeping it as a multiplier instead of dividing.",
    "Confusing the adjacent and opposite sides relative to the reference angle.",
    "Believing that 10 to the power of 3 is 30 instead of 1000.",
    "Assuming 'average' always refers to the mean in every technical report."
  ]
}

{
  "teachChecks": [
    {
      "title": "Fractions, Percentages, and Indices",
      "basicQuestions": [
        {
          "questionText": "What mathematical term refers to the small power numbers used to represent multipliers like kilo or milli?",
          "answerGuidance": [
            "Indices",
            "Powers",
            "Powers of 10"
          ],
          "hint": "It is the term for the small number written above and to the right of a base number.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "In electrical work, how are values such as component tolerances or circuit efficiency typically expressed?",
          "answerGuidance": [
            "Percentages",
            "Percent",
            "Percentage"
          ],
          "hint": "Think of a value out of 100.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which specific power of 10 is used to represent the multiplier 'kilo' in electrical units?",
          "answerGuidance": [
            "10 to the power of 3",
            "10^3",
            "103"
          ],
          "hint": "Kilo represents one thousand.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        }
      ],
      "deeperQuestionText": "Why is it more practical for an electrician to use indices (powers of 10) rather than writing out full numerical values when dealing with units like kilo or milli?",
      "deeperAnswerGuidance": [
        "Reduces the risk of errors with multiple zeros",
        "Provides a standardized way to represent very large or small values",
        "Makes calculations with multipliers more manageable",
        "Aligns with standard SI unit prefixes"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2"
      ],
      "hint": "Think about the difficulty of writing out numbers like 0.000001 or 1,000,000 repeatedly."
    },
    {
